import {
    PaymentLinkInfo,
    CheckoutSessionInfo,
    PaymentProcessRequest,
    PaymentProcessResponse,
} from '../types/payment.types';

// Mock data constants are now flattened directly into links and sessions

const mockPaymentLink: PaymentLinkInfo = {
    id: 'pl-abcd123',
    title: 'Boutique SharePay',
    description: 'Paiement pour commande #1024',
    logoUrl: 'data:image/png;base64,',
    amount: 15000,
    currency: 'XAF',
    currencyName: 'F CFA',
    type: 'FREE',
    collectCustomerInfo: false,
    status: 'ACTIVE',
    createdAt: new Date().toISOString(),
    expiresAt: new Date(Date.now() + 15 * 60000).toISOString(), // 15 mins from now
};

const mockCheckoutSession: CheckoutSessionInfo = {
    id: 'chk-5678xyz',
    reference: 'REF-2026-XYZ',
    title: 'Boutique SharePay',
    description: 'Achat via API SharePay',
    logoUrl: 'https://upload.wikimedia.org/wikipedia/commons/c/c1/Google_%22G%22_logo.svg',
    type: 'ORDER',
    amount: 50,
    currency: 'XOF',
    currencyName: 'F CFA',
    status: 'PENDING',
    callbackUrl: 'https://example.com/callback',
    createdAt: new Date().toISOString(),
    expiresAt: new Date(Date.now() + 15 * 60000).toISOString(), // 15 mins from now
    // Sample pre-fill data
    fullName: 'Jean Dupont',
    email: 'jean.dupont@example.com',
    phoneNumber: '+237670000000',
    paymentMethod: 'ORANGE_MONEY'
};

class PaymentService {
    /**
     * Retrieves payment link details by ID
     */
    async getPaymentLinkInfo(id: string): Promise<PaymentLinkInfo> {
        return new Promise((resolve, reject) => {
            setTimeout(() => {
                if (id === 'error') {
                    reject(new Error("Lien de paiement introuvable ou expiré."));
                } else {
                    // Return a modified mock to simulate dynamic data
                    resolve({
                        ...mockPaymentLink,
                        id,
                    });
                }
            }, 800); // simulate network latency
        });
    }

    /**
     * Retrieves checkout session details by code
     */
    async getCheckoutSession(code: string): Promise<CheckoutSessionInfo> {
        return new Promise((resolve, reject) => {
            setTimeout(() => {
                if (code === 'error') {
                    reject(new Error("Session de paiement invalide."));
                } else {
                    resolve({
                        ...mockCheckoutSession,
                        reference: `CODE-${code.toUpperCase()}`,
                    });
                }
            }, 800);
        });
    }

    /**
     * Processes the payment
     */
    async processPayment(payload: PaymentProcessRequest): Promise<PaymentProcessResponse> {
        return new Promise((resolve, reject) => {
            // Simulate validation error
            if ((payload.paymentMethod === 'ORANGE_MONEY' || payload.paymentMethod === 'MTN_MONEY') && !payload.phoneNumber) {
                return reject(new Error("Le numéro de téléphone est requis pour le Mobile Money."));
            }

            setTimeout(() => {
                // Simulate a success scenario
                resolve({
                    success: true,
                    transactionId: `TXN-${Math.random().toString(36).substring(2, 10).toUpperCase()}`,
                    message: "Paiement effectué avec succès.",
                });
            }, 1500); // 1.5s simulated processing time
        });
    }
}

export const paymentService = new PaymentService();
